    def set_vhost_limits(self, vhost_name: str, max_connections: int = -1, 
                        max_queues: int = -1) -> bool:
        vhost_encoded = urllib.parse.quote(vhost_name, safe='')
        
        if max_connections > 0:
            endpoint = f"vhost-limits/{vhost_encoded}/max-connections"
            data = {"value": max_connections}
            response = self._make_request("PUT", endpoint, data)
            
            if response.status_code not in [201, 204]:
                print(f"Failed to set max connections: {response.status_code}")
